// Execution Result Container
export class Execution {
    code;
    context;
    /**
     * All results from the execution
     */
    results = [];
    /**
     * Accumulated stdout and stderr
     */
    logs = {
        stdout: [],
        stderr: []
    };
    /**
     * Execution error if any
     */
    error;
    /**
     * Execution count (for interpreter)
     */
    executionCount;
    constructor(code, context) {
        this.code = code;
        this.context = context;
    }
    /**
     * Convert to a plain object for serialization
     */
    toJSON() {
        return {
            code: this.code,
            logs: this.logs,
            error: this.error,
            executionCount: this.executionCount,
            results: this.results.map((result) => ({
                text: result.text,
                html: result.html,
                png: result.png,
                jpeg: result.jpeg,
                svg: result.svg,
                latex: result.latex,
                markdown: result.markdown,
                javascript: result.javascript,
                json: result.json,
                chart: result.chart,
                data: result.data
            }))
        };
    }
}
// Implementation of Result
export class ResultImpl {
    text;
    html;
    png;
    jpeg;
    svg;
    latex;
    markdown;
    javascript;
    json;
    chart;
    data;
    // eslint-disable-next-line @typescript-eslint/no-explicit-any -- raw SSE data has dynamic shape
    constructor(raw) {
        this.text = raw.text || raw.data?.['text/plain'];
        this.html = raw.html || raw.data?.['text/html'];
        this.png = raw.png || raw.data?.['image/png'];
        this.jpeg = raw.jpeg || raw.data?.['image/jpeg'];
        this.svg = raw.svg || raw.data?.['image/svg+xml'];
        this.latex = raw.latex || raw.data?.['text/latex'];
        this.markdown = raw.markdown || raw.data?.['text/markdown'];
        this.javascript = raw.javascript || raw.data?.['application/javascript'];
        this.json = raw.json || raw.data?.['application/json'];
        this.chart = raw.chart;
        this.data = raw.data;
    }
    formats() {
        const fmts = [];
        if (this.text)
            fmts.push('text');
        if (this.html)
            fmts.push('html');
        if (this.png)
            fmts.push('png');
        if (this.jpeg)
            fmts.push('jpeg');
        if (this.svg)
            fmts.push('svg');
        if (this.latex)
            fmts.push('latex');
        if (this.markdown)
            fmts.push('markdown');
        if (this.javascript)
            fmts.push('javascript');
        if (this.json)
            fmts.push('json');
        if (this.chart)
            fmts.push('chart');
        return fmts;
    }
}
